import { COMMON_IMAGE_FRAGMENT } from "@graphql/fragments/common";
import { gql } from "graphql-request";

export const CART_API_PAGES_QUERY = gql`
  ${COMMON_IMAGE_FRAGMENT}
  query CartApiPages($locale: I18NLocaleCode, $isDevelopmentMode: Boolean) {
    pages(
      locale: $locale
      pagination: { limit: 40 }
      filters: { isEcom: { eq: true }, isDevelopmentMode: { eq: $isDevelopmentMode } }
    ) {
      data {
        id
        attributes {
          __typename
          urlPath
          productDiscountCode {
            data {
              id
              attributes {
                code
                perceivedDiscountPercentage
                perceivedOtpDiscountPercentage
              }
            }
          }
          products {
            data {
              id
              attributes {
                productOtpID
                otpVariantID
                productSubID
                subscriptionVariantID
                image {
                  ...ImageCommonFragment
                }
              }
            }
          }
        }
      }
    }
  }
`;

