import { gql } from "graphql-request";

export const CART_PAGE_QUERY = gql`
  query cartPage($locale: I18NLocaleCode) {
    cartPage(locale: $locale) {
      data {
        attributes {
          title
          subHeading
          cartBumpsTitle
          cartTotalTheme
          showProgressToFreeShipping
          showQuantitySelector
          freeGiftOptInOffer {
            data {
              id
            }
          }
          cartBumps {
            cartBumpOffer {
              data {
                id
              }
            }
            hideIfInCart {
              data {
                id
              }
            }
            benefitTitle
            benefitPoints {
              label
            }
            vetQuote {
              data {
                id
                attributes {
                  quote
                  vet {
                    data {
                      attributes {
                        fullname
                        honours
                        short_description
                        avatar {
                          data {
                            attributes {
                              url
                              width
                              height
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
            ingredientsDesign
          }
        }
      }
    }
  }
`;

