import { gql } from "graphql-request";
import { COMMON_IMAGE_FRAGMENT } from "../fragments/common/image";

export const BUMP_OFFERS_QUERY = gql`
  ${COMMON_IMAGE_FRAGMENT}
  query BumpOffers($locale: I18NLocaleCode, $isCart: Boolean) {
    bumpOffers(locale: $locale, filters: { isCart: { eq: $isCart } }, pagination: { limit: 40 }) {
      data {
        id
        attributes {
          __typename
          label
          isCart
          painPoint
          description
          otpVariantID
          subscriptionVariantID
          productOtpID
          productSubID
          backgroundColour
          discountCode {
            data {
              id
              attributes {
                code
                perceivedDiscountPercentage
                perceivedOtpDiscountPercentage
              }
            }
          }
          product {
            data {
              id
              attributes {
                sku
                petType
                image {
                  ...ImageCommonFragment
                }
                parentSku {
                  data {
                    attributes {
                      name
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
`;

