import { gql } from "graphql-request";
import {
  CUSTOMER_REVIEWS_FRAGMENT,
  EXPLORE_OTHER_PRODUCTS_FRAGMENT,
  FEEDBACK_FORM_FRAGMENT,
  PET_FEEDING_TIPS_FRAGMENT,
  PET_HEALTH_TIPS_FRAGMENT,
  PRODUCT_COST_COMPARISON_FRAGMENT,
  PRODUCT_DETAILS_FRAGMENT,
  PRODUCT_HIGHLIGHTS_FRAGMENT,
  PROGRESS_INDICATOR_FRAGMENT,
  UPDATE_DELIVERY_DATE_FRAGMENT,
} from "./fragments/journey";

export const USER_JOURNEY_PATHS = gql`
  query userJourneyPaths {
    userJourneys(pagination: { limit: 100 }) {
      data {
        attributes {
          locale
          urlPath
        }
      }
    }
  }
`;

export const USER_JOURNEY_QUERY = gql`
  ${CUSTOMER_REVIEWS_FRAGMENT}
  ${EXPLORE_OTHER_PRODUCTS_FRAGMENT}
  ${FEEDBACK_FORM_FRAGMENT}
  ${PET_FEEDING_TIPS_FRAGMENT}
  ${PET_HEALTH_TIPS_FRAGMENT}
  ${PRODUCT_COST_COMPARISON_FRAGMENT}
  ${PRODUCT_DETAILS_FRAGMENT}
  ${PRODUCT_HIGHLIGHTS_FRAGMENT}
  ${PROGRESS_INDICATOR_FRAGMENT}
  ${UPDATE_DELIVERY_DATE_FRAGMENT}
  query userJourneys($locale: I18NLocaleCode!, $path: String!) {
    userJourneys(locale: $locale, filters: { urlPath: { eq: $path } }) {
      data {
        attributes {
          urlPath
          seo {
            title
            description
            isIndexable
            ogImage {
              data {
                id
                attributes {
                  url
                  width
                  height
                }
              }
            }
          }
          banner {
            mobile {
              data {
                attributes {
                  url
                  width
                  height
                  alternativeText
                }
              }
            }
            desktop {
              data {
                attributes {
                  url
                  width
                  height
                  alternativeText
                }
              }
            }
          }
          journeys {
            id
            label
            journeyId
            steps {
              data {
                id
                attributes {
                  stepId
                  content {
                    __typename
                    ...CustomerReviewsFragment
                    ...ExploreOtherProductsFragment
                    ...FeedbackFormFragment
                    ...PetFeedingTipsFragment
                    ...PetHealthTipsFragment
                    ...ProductCostComparisonFragment
                    ...ProductDetailsFragment
                    ...ProductHighlightsFragment
                    ...ProgressIndicatorFragment
                    ...UpdateDeliveryDateFragment
                  }
                }
              }
            }
          }
          page {
            data {
              id
              attributes {
                products {
                  data {
                    id
                    attributes {
                      ingredients(pagination: { limit: 35 }) {
                        productIngredient {
                          data {
                            id
                            attributes {
                              label
                              description
                              fullLabel
                              shortLabel
                              shortDescription
                              missingInCompetitors
                              image {
                                data {
                                  id
                                  attributes {
                                    url
                                    width
                                    height
                                    alternativeText
                                  }
                                }
                              }
                            }
                          }
                        }
                        id
                        amountLabel
                        showAsHighlight
                        isHiddenInList
                        ingredientSubitems {
                          label
                          amountLabel
                        }
                      }
                      productType
                      usageRecommendations {
                        id
                        dailyAmount
                        monthlyAmount
                        dogSize {
                          data {
                            attributes {
                              label
                              weight
                              icon {
                                data {
                                  attributes {
                                    url
                                  }
                                }
                              }
                            }
                          }
                        }
                      }
                      usageInstructions
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
`;

