import { gql } from "graphql-request";

export const SEARCH = gql`
  query SearchData($locale: I18NLocaleCode, $currentTime: DateTime, $isDevelopmentMode: Boolean) {
    pages(
      locale: $locale
      filters: { isEcom: { eq: true }, isDevelopmentMode: { eq: $isDevelopmentMode } }
      pagination: { limit: 35 }
    ) {
      data {
        id
        attributes {
          title
          urlPath
          okendoStarRating
          productDiscountCode {
            data {
              id
              attributes {
                code
                perceivedDiscountPercentage
                perceivedOtpDiscountPercentage
              }
            }
          }
          products {
            data {
              id
              attributes {
                name
                petType
                subscriptionVariantID
                otpVariantID
                productOtpID
                productSubID
                image {
                  data {
                    id
                    attributes {
                      url
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
    promos(
      locale: $locale
      filters: { startDateTime: { lte: $currentTime }, endDateTime: { gte: $currentTime } }
    ) {
      data {
        id
        attributes {
          title
          startDateTime
          endDateTime
          overrides {
            __typename
            ... on ComponentOverridesPageOverrides {
              page {
                data {
                  id
                  attributes {
                    urlPath
                  }
                }
              }
              pageVariant {
                data {
                  id
                  attributes {
                    urlPath
                  }
                }
              }
              discountCode {
                data {
                  id
                  attributes {
                    code
                    perceivedDiscountPercentage
                    perceivedOtpDiscountPercentage
                  }
                }
              }
            }
          }
        }
      }
    }
  }
`;

