import { gql } from "graphql-request";
import { COMMON_IMAGE_FRAGMENT } from "./fragments/common/image";

export const NAVIGATION_AND_CONFIG = gql`
  ${COMMON_IMAGE_FRAGMENT}
  query NavigationAndConfig($locale: I18NLocaleCode, $currentTime: DateTime!) {
    ecomConfig(locale: $locale) {
      data {
        id
        attributes {
          homePage {
            data {
              id
            }
          }
          trustScore
          trustpilotReviewsCount
          menuDropdownImageURL
          menuDropdownImage {
            data {
              attributes {
                previewUrl
                url
              }
            }
          }
        }
      }
    }
    navigations(locale: $locale, pagination: { limit: 70 }) {
      data {
        id
        attributes {
          label
          url
          navigationId
          childItems {
            data {
              id
              attributes {
                label
                url
                navigationId
                shortDescription
                columnsPerRow
                image {
                  ...ImageCommonFragment
                }
                mobileImage {
                  ...ImageCommonFragment
                }
              }
            }
          }
        }
      }
    }
    navigationCollections(locale: $locale, filters: { app: { eq: "ecom" } }) {
      data {
        id
        attributes {
          app
          device
          name
          items {
            label
            childLinks {
              data {
                attributes {
                  label
                  navigationId
                  url
                  columnsPerRow
                  image {
                    ...ImageCommonFragment
                  }
                  mobileImage {
                    ...ImageCommonFragment
                  }
                  childItems {
                    data {
                      attributes {
                        label
                        navigationId
                        url
                        shortDescription
                        image {
                          ...ImageCommonFragment
                        }
                        mobileImage {
                          ...ImageCommonFragment
                        }
                      }
                    }
                  }
                }
              }
            }
            urlOrAnchor
            navigationId
            menuLayout
          }
        }
      }
    }
    promos(
      locale: $locale
      filters: {
        isEcomEnabled: { eq: true }
        startDateTime: { lte: $currentTime }
        endDateTime: { gte: $currentTime }
      }
    ) {
      data {
        id
        attributes {
          overrides {
            __typename
            ... on ComponentOverridesEcomHeader {
              menuDropdownImageURL
              menuDropdownImage {
                data {
                  attributes {
                    previewUrl
                    url
                  }
                }
              }
            }
          }
        }
      }
    }
  }
`;

