import { PageEntity, PromoEntityResponseCollection } from "@generated/strapiGraphql";
import { PDP_FREE_GIFTS_QUERY } from "@graphql/page";
import { getFreeGifts } from "@queries/cart/getfreeGifts";
import { getPagesPrices } from "@queries/getPagesPrices";
import { getPromos } from "@queries/getPromos";
import { applyCollectionOverrides } from "@queries/overrides/entities/applyCollectionOverrides";
import { applyPromoOverrides } from "@queries/overrides/entities/applyPromoOverrides";
import { ExtendedPageEntity } from "@queries/overrides/types";
import { FlattenedFreeGiftsResponse, FlattenedPromoResponseCollection } from "@typings/graphql";
import { i18nLocales } from "@typings/i18n";
import { ProductPageData } from "@typings/page";
import { oneQuantity } from "@utils/constants/pdp";
import { flattenPromos } from "@utils/helpers/flattenPromos";
import { getPage } from "./getPage";
import { getProductPage } from "./getProductPage";

type GetPageData = (
  path: string,
  isEcom: boolean,
  locale: i18nLocales,
  config?: {
    applyPromo?: boolean;
    customOverrides?: (page: PageEntity) => PageEntity;
    quantities?: string[];
    productDiscountCode?: string;
    injectDiscountCodes?: (discountCodes: string[]) => string[];
    injectPage?: (page: ProductPageData) => ProductPageData;
  }
) => Promise<{
  page?: ProductPageData | null;
  freeGifts: FlattenedFreeGiftsResponse[] | null;
  promos: FlattenedPromoResponseCollection | null | undefined;
}>;

export const getPageData: GetPageData = async (path, isEcom, locale, config) => {
  let promos: PromoEntityResponseCollection | null = null;
  let freeGifts: FlattenedFreeGiftsResponse[] | null = null;

  // gets the page from cms
  let page = await getPage(path, isEcom, locale);
  if (!page) return { page: null, promos: null, freeGifts: null };

  // retrieves all free gift product IDs to validate discontinued items in the cart
  if (isEcom) {
    freeGifts = await getFreeGifts(locale, { query: PDP_FREE_GIFTS_QUERY });
  }

  // gets the promos and applies promo overrides
  if (config?.applyPromo !== false) {
    const isEcomEnabled = isEcom ? true : undefined;
    promos = await getPromos(locale as i18nLocales, isEcomEnabled);
    page = applyPromoOverrides(page, promos);

    // if promo bestsellers on pdp then: (const relatedPages = await getPagesPrices() - flattenedPromos changed to null as its handled here):
    if (page.attributes?.relatedPages?.data.length) {
      page.attributes.relatedPages.data = applyCollectionOverrides(
        page.attributes.relatedPages,
        promos
      ) as ExtendedPageEntity[];
    }
  }

  // apply custom overrides
  if (config?.customOverrides) {
    page = config.customOverrides(page);
  }

  // flattens promos
  const flattenedPromos = flattenPromos(promos);

  // flattens pages and fetches the prices for products and bump offers and adds them to the page
  let flattenedPage = await getProductPage(page, {
    quantities: config?.quantities ?? [],
    productDiscountCode: config?.productDiscountCode,
    injectDiscountCodes: config?.injectDiscountCodes,
    injectPage: config?.injectPage,
  });

  // gets the prices for related pages
  if (flattenedPage?.relatedPages && flattenedPage?.relatedPages.length > 0) {
    const relatedPages = await getPagesPrices(flattenedPage.relatedPages, null, oneQuantity);
    flattenedPage = { ...flattenedPage, relatedPages };
  }

  return { page: flattenedPage, promos: flattenedPromos, freeGifts: freeGifts };
};

