import { getProductPrices, ProductPricePayloadItem } from "@queries/getProductPrices";
import { ExtendedPageEntity } from "@queries/overrides/types";
import { FlattenedPageResponse } from "@typings/graphql";
import { ProductPageData } from "@typings/page";
import { ProductOverrides, ProductPrice } from "@typings/product";
import { MAX_CART_QUANTITY } from "@utils/constants/cart";
import { OTP } from "@utils/constants/pdp";
import { flattenStrapi } from "@utils/helpers/flattenStrapi";
import { generateArray } from "@utils/helpers/generateArray";

type PurchaseType = "subscription" | "otp";

/**
 * The checkout API requires an array of objects with the following structure for each quantity:
 * {
 *   quantity: number,
 *   variant_id: string
 * }
 *
 * @returns Array<ProductQuantityObject>
 * @param page
 * @param purchaseType
 * @param quantityOptions
 * @param overrides
 */
export function buildQuantityArray(
  page: ProductPageData | FlattenedPageResponse,
  purchaseType: PurchaseType,
  quantityOptions: string[] = []
): Array<ProductPricePayloadItem> {
  if (!page) throw Error("Page entity is not found");

  if (!page.products) throw Error("Products not defined on Page entity");

  if (!quantityOptions.length) quantityOptions = generateArray(MAX_CART_QUANTITY);

  const productIdKey = purchaseType === OTP ? "productOtpID" : "productSubID";

  const quantities = page.products.flatMap((product) => {
    return quantityOptions
      .map((quantity) => {
        const productId = product[productIdKey];

        if (!productId) return null;

        return {
          quantity: parseInt(quantity),
          product_id: productId,
        };
      })
      .filter((item): item is ProductPricePayloadItem => item !== null);
  });

  return quantities;
}

/**
 * Construct product page data with prices.
 */
function constructProductPageDataWithPrices(
  page: ProductPageData,
  prices: ProductPrice[]
): ProductPageData {
  if (!page.products) throw Error("Products not defined on Page entity");

  if (!page.subBumpOffers) throw Error("Subscription bump offers not defined on Page entity");

  if (!page.otpBumpOffers) throw Error("One-Time Purchase bump offers not defined on Page entity");

  // Construct a new page object with the prices
  return {
    ...page,
    // Add prices to the products
    products: page.products.map((product) => {
      const otpPrices = prices.filter((price) => price.product_id == product.productOtpID);
      const subPrices = prices.filter((price) => price.product_id == product.productSubID);

      return {
        ...product,
        prices: {
          subPrices,
          otpPrices,
        },
      };
    }),

    // Add prices to the subscription bump offer
    subBumpOffers: page.subBumpOffers.map((offer) => {
      const priceData = prices.find((price) => {
        if (!offer.subscriptionVariantID)
          throw Error(`Subscription variant ID missing on bump offer ${offer.label}`);

        return price.product_id.toString() === offer.productSubID.toString();
      });

      if (!priceData) throw Error(`Price data missing on subscription bump offer ${offer.label}`);

      return {
        ...offer,
        quantity: 1,
        price: {
          salePrice: priceData.discounted_price,
          rrp: priceData.perceived_rrp,
        },
      };
    }),

    // Add prices to the One-Time Purchase bump offer
    otpBumpOffers: page.otpBumpOffers.map((offer) => {
      const priceData = prices.find((price) => {
        if (!offer.otpVariantID)
          throw Error(`One-Time Purchase variant ID missing on bump offer ${offer.label}`);

        return price.product_id.toString() === offer.productOtpID.toString();
      });

      if (!priceData)
        throw Error(`Price data missing on one-time purchase bump offer ${offer.label}`);

      return {
        ...offer,
        quantity: 1,
        price: {
          salePrice: priceData.discounted_price,
          rrp: priceData.perceived_rrp,
        },
      };
    }),
  };
}

/**
 * getProductPage
 * Given a path, return the product page data including prices for each product and bump offfer product, taking into account any discount codes.
 */
export const getProductPage = async (
  basePage: ExtendedPageEntity,
  overrides?: ProductOverrides
) => {
  const flattenedPage = flattenStrapi(basePage) as ProductPageData;

  const injectPage = overrides?.injectPage || ((page) => page);
  const injectDiscountCodes = overrides?.injectDiscountCodes || ((discountCodes) => discountCodes);
  const page = injectPage(flattenedPage as ProductPageData);

  if (!page) return null;

  if (!page.products) throw Error("Products not defined on Page entity");

  if (!page.subBumpOffers) throw Error(`Subscription bump offers missing on ${page.title}`);

  if (!page.otpBumpOffers) throw Error(`One-time purchase bump offers missing on ${page.title}`);

  const quantityOptions = overrides?.quantities || [];

  /* TODO: subBumpOffers is required, there maybe a funnel where we don't need a bump offer */
  if (page.subBumpOffers) {
    const subscriptionItems = buildQuantityArray(page, "subscription", quantityOptions);
    const otpItems = buildQuantityArray(page, "otp", quantityOptions);

    const subBumpOfferItems = page.subBumpOffers.map((bumpOffer) => {
      const subId = bumpOffer.productSubID;
      if (!subId) throw Error(`Subscription variant ID missing on bump offer ${bumpOffer.label}`);

      return {
        quantity: 1,
        product_id: subId,
      };
    });

    const otpBumpOfferItems = page.otpBumpOffers.map((bumpOffer) => {
      const otpId = bumpOffer.productOtpID;
      if (!otpId)
        throw Error(`One-time purchase variant ID missing on bump offer ${bumpOffer.label}`);

      return {
        quantity: 1,
        product_id: otpId,
      };
    });

    const items = [...subscriptionItems, ...otpItems, ...subBumpOfferItems, ...otpBumpOfferItems];

    /**
     * Discount codes
     */
    if (!page.productDiscountCode || !page.productDiscountCode.code)
      throw Error(`Discount code missing on ${page.title}`);

    page.productDiscountCode.code = overrides?.productDiscountCode ?? page.productDiscountCode.code;

    const bumpOfferDiscountCodes = page.subBumpOffers.map((bumpOffer) => {
      if (!bumpOffer.discountCode || !bumpOffer.discountCode.code)
        throw Error(`Discount code missing on ${bumpOffer.label}`);

      return bumpOffer.discountCode.code;
    });

    const discountCodes = injectDiscountCodes([
      page.productDiscountCode.code,
      ...[...new Set(bumpOfferDiscountCodes)],
    ]);

    // Get the prices. This is where the API call to thec checkout app is made.
    const prices = await getProductPrices(items, discountCodes);

    const pageData = constructProductPageDataWithPrices(page, prices);

    return pageData;
  }
};

