import { ProductPrice } from "@typings/product";
import { CURRENT_COUNTRY_CODE } from "@utils/constants/country";
import { MAX_CHECKOUT_RETRIES } from "@utils/constants/general";
import { VARIANT_API_V2_URL } from "@utils/constants/links";
import { addDelay } from "@utils/helpers/addDelay";

type Pricing = {
  unit_price: number;
  line_item_price: number;
  discounted_unit_price: number;
  discounted_line_item_price: number;
  line_item_discount_amount: number;
  line_item_discount_percentage: number;
  is_free: boolean;
};

type LineItem = {
  product_id: number;
  quantity: number;
  sku: string;
  schedule: string;
  product_name: string;
  pet_size: string;
  image_url: string;
  is_upsell: boolean;
  pricing: Pricing;
};

interface PricingObject {
  subtotal: number;
  discounted_subtotal: number;
  discounted_subtotal_with_shipping: number;
  taxes: number;
  tax_rate: number;
  total_savings: number;
  order_total: number;
  highest_subscription_percentage_discount: number;
  has_subscription_discount: boolean;
  has_free_gift: boolean;
  has_free_shipping: boolean;
}

export type CheckoutApiResponse = {
  data: {
    pricing: PricingObject;
    line_items: LineItem[];
    discount_codes: string[];
  };
};

export interface ProductPricePayloadItem {
  quantity: number;
  product_id: string | number;
}

export interface ProductPricePayload {
  line_items: ProductPricePayloadItem[];
}

export interface CheckoutPayload extends ProductPricePayload {
  discount_codes: string[];
}

export type FetchProductPrices = (
  payload: CheckoutPayload,
  retries?: number
) => Promise<CheckoutApiResponse>;

const formatProductPrices = (results: CheckoutApiResponse): ProductPrice[] => {
  return results.data.line_items.map((item) => ({
    product_id: `${item.product_id}`,
    quantity: item.quantity,
    title: item.product_name,
    price: item.pricing.line_item_price,
    discounted_price: item.pricing.discounted_line_item_price,
    country: CURRENT_COUNTRY_CODE,
    image: item.image_url,
    split_price: item.pricing.discounted_line_item_price,
    perceived_rrp: item.pricing.line_item_price,
    splitFlag: false,
    title_index: `0`,
    variant_id: `${item.product_id}`,
  }));
};

export const fetchProductPrices: FetchProductPrices = async (
  payload,
  retries = MAX_CHECKOUT_RETRIES
) => {
  try {
    const response = await fetch(`${VARIANT_API_V2_URL}`, {
      method: "POST",
      body: JSON.stringify(payload),
    });

    if (!response.ok)
      throw new Error(`Checkout API - HTTP error! \n 
    POST ${VARIANT_API_V2_URL} - ${response.status} ${response.statusText}`);

    return await response.json();
  } catch (err) {
    if (retries > 0) {
      console.error(`Checkout API - Failed to fetch prices - ${retries} retries remaining`);

      await addDelay(100);
      return fetchProductPrices(payload, retries - 1);
    } else {
      console.error(
        "Chekout API v2 - Couldn't fetch prices for: ",
        payload.line_items.map((item) => item.product_id).join(",")
      );
      throw Error("Checkout API v2 - Terminating api calls after failed retries");
    }
  }
};

const getProductPrices = async (line_items: ProductPricePayloadItem[], discountCodes: string[]) => {
  const payload = {
    line_items,
    discount_codes: discountCodes,
  };

  const data = await fetchProductPrices(payload);

  if (!data.data || !data.data.line_items.length)
    throw Error("Checkout API v2 - Prices missing from price API response");

  return formatProductPrices(data);
};

export { getProductPrices };

