import {
  FlattenedPageResponseCollection,
  FlattenedPromoResponseCollection,
} from "@typings/graphql";
import { getPageOverrides } from "@utils/helpers/getPageOverrides";
import { stripPriceDetails } from "@utils/helpers/stripPriceDetails";
import { getProductPrices } from "./getProductPrices";
import { buildQuantityArray } from "./products/getProductPage";

export const getPagesPrices = async (
  pages: FlattenedPageResponseCollection,
  promos: FlattenedPromoResponseCollection | null,
  quantities: string[]
) => {
  if (!pages || !Array.isArray(pages)) return [];

  return await Promise.all(
    pages.map(async (page) => {
      if (!page.products?.length) throw new Error(`No products for: ${page.title}`);

      const { promoOverride } = getPageOverrides(page, promos);
      const productDiscountCode = promoOverride?.discountCode || page.productDiscountCode;

      const subscriptionItems = buildQuantityArray(page, "subscription", quantities);
      const otpItems = buildQuantityArray(page, "otp", quantities);

      const prices = await getProductPrices(
        [...otpItems, ...subscriptionItems],
        [productDiscountCode?.code || ""]
      );

      const products = page.products.map((product) => ({
        ...product,
        prices: {
          otp: prices
            .filter((price) => price.product_id == product.productOtpID)
            .map(stripPriceDetails),
          sub: prices
            .filter((price) => price.product_id == product.productSubID)
            .map(stripPriceDetails),
        },
      }));

      return {
        ...page,
        products,
        productDiscountCode,
      };
    })
  );
};

