import { getProductPrices } from "@queries/getProductPrices";
import { FlattenedBumpOfferEntity } from "@typings/graphql";
import { oneQuantity } from "@utils/constants/pdp";
import { stripPriceDetails } from "@utils/helpers/stripPriceDetails";

const buildQuantitiesArray = (quantities: string[], productId?: number | null) => {
  if (!productId) return [];

  return quantities.map((quantity) => ({
    quantity: parseInt(quantity),
    product_id: `${productId}`,
  }));
};

export const getBumpOffersPrices = async (bumpOffers: FlattenedBumpOfferEntity[] | null) => {
  if (!bumpOffers) return [];

  return await Promise.all(
    bumpOffers.map(async (offer) => {
      const { productOtpID, productSubID, discountCode } = offer;

      if (!productOtpID) {
        throw Error(`Product IDs are required for bump offer: ${offer.label} - (${offer.id})`);
      }

      const subscriptionItems = buildQuantitiesArray(oneQuantity, productSubID);
      const otpItems = buildQuantitiesArray(oneQuantity, productOtpID);

      const prices = await getProductPrices(
        [...otpItems, ...subscriptionItems],
        [discountCode?.code || ""]
      );

      return {
        ...offer,
        prices: {
          otp: prices.filter((price) => price.product_id == productOtpID).map(stripPriceDetails),
          sub: prices.filter((price) => price.product_id == productSubID).map(stripPriceDetails),
        },
      };
    })
  );
};

