import { CART_API_BUMP_OFFERS_QUERY } from "@graphql/cart/api/bumpOffers";
import { CART_API_FREE_GIFTS_QUERY } from "@graphql/cart/api/freeGift";
import { CART_API_PAGES_QUERY } from "@graphql/cart/api/page";
import { getBumpOffers } from "@queries/cart/getBumpOffers";
import { getPagesAndPromos } from "@queries/cart/getPagesAndPromos";
import { getFreeGifts } from "@queries/cart/getfreeGifts";
import { i18nLocales } from "@typings/i18n";
import type { NextApiRequest, NextApiResponse } from "next";
import { i18n } from "next-i18next.config";

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  const locale = (req.query.locale ?? i18n.defaultLocale) as i18nLocales;

  try {
    const [{ pages }, bumpOffers, freeGifts] = await Promise.all([
      getPagesAndPromos(locale, { pagesQuery: CART_API_PAGES_QUERY }),
      getBumpOffers(locale, null, { query: CART_API_BUMP_OFFERS_QUERY }),
      getFreeGifts(locale, { query: CART_API_FREE_GIFTS_QUERY }),
    ]);

    res
      .status(200)
      .setHeader(
        "Cache-Control",
        "public, max-age=3600, s-maxage=1800, stale-while-revalidate=86400, stale-if-error=86400"
      )
      .json({
        pages: pages.map(({ productDiscountCode, ...page }) => page),
        bumpOffers: bumpOffers.map(({ discountCode, ...offer }) => offer),
        freeGifts,
      });
  } catch (error: any) {
    res
      .status(500)
      .send({ error: { message: "Failed to fetch cart data", details: error?.message } });
  }
}

