import { Maybe, PromoEntityResponseCollection, Query } from "@generated/strapiGraphql";
import { graphqlClient } from "@getGraphqlClient";
import { PAGES_QUERY } from "@graphql/cart/page";
import { CART_FORCED_PROMO_QUERY, CART_PROMOS_QUERY } from "@graphql/cart/promo";
import { getPagesPrices } from "@queries/getPagesPrices";
import { applyCollectionOverrides } from "@queries/overrides/entities/applyCollectionOverrides";
import { i18nLocales } from "@typings/i18n";
import { MAX_CART_QUANTITY } from "@utils/constants/cart";
import { isDevelopmentMode } from "@utils/helpers/environments/flags";
import { flattenStrapi } from "@utils/helpers/flattenStrapi";
import { generateArray } from "@utils/helpers/generateArray";
import { getCurrentTime } from "@utils/helpers/getCurrentTime";

type QueryOptions = {
  pagesQuery?: string;
  promosQuery?: string;
};

export const getPagesAndPromos = async (locale: i18nLocales, options?: QueryOptions) => {
  const forcedPromoId = process.env.NEXT_PUBLIC_FORCED_PROMO_ID ?? "Active";
  const getActivePromos = forcedPromoId === "Active";

  const { pagesQuery = PAGES_QUERY, promosQuery = CART_PROMOS_QUERY } = options || {};

  const PagesRes = (await graphqlClient.request(pagesQuery, {
    locale,
    isDevelopmentMode,
  })) as Query;

  const PromosRes = (await graphqlClient.request(
    getActivePromos ? promosQuery : CART_FORCED_PROMO_QUERY,
    {
      locale,
      isEcomEnabled: true,
      currentTime: getCurrentTime(),
      promoId: forcedPromoId,
    }
  )) as Query & {
    draftPromos: Maybe<PromoEntityResponseCollection>;
    livePromos: Maybe<PromoEntityResponseCollection>;
  };

  const promos = getActivePromos ? PromosRes.promos : PromosRes.draftPromos ?? PromosRes.livePromos;

  const pageWithOverrides = applyCollectionOverrides(PagesRes.pages, promos);

  const pagesWithPrices = await getPagesPrices(
    flattenStrapi(pageWithOverrides),
    null,
    generateArray(MAX_CART_QUANTITY)
  );

  return {
    pages: pagesWithPrices,
    promos: flattenStrapi(PromosRes.promos),
  };
};

