import {
  PageEntityResponseCollection,
  PageRelationResponseCollection,
  PromoEntityResponseCollection,
} from "@generated/strapiGraphql";
import { applyPromoOverrides } from "@queries/overrides/entities/applyPromoOverrides";

export const applyCollectionOverrides = (
  pages: PageEntityResponseCollection | PageRelationResponseCollection | null,
  promos: PromoEntityResponseCollection | null
) => {
  return (
    pages?.data.map((basePage) => {
      const page = applyPromoOverrides(basePage, promos);
      if (!page.attributes?.promo) return page;
      // remove extra properties
      const { otpFreeShipping, quantitySelectorType, whySubscribeText, ...pageAttributes } =
        page.attributes;

      return {
        ...page,
        attributes: {
          ...pageAttributes,
          promo: {
            id: pageAttributes.promo?.id,
            title: pageAttributes.promo?.title,
          },
        },
      };
    }) || []
  );
};

