import { Review, OkendoReview } from "@typings/okendo";
import { DEFAULT_REVIEW_COUNT, DEFAULT_REVIEW_ORDER } from "@utils/constants/okendo";

export const getOkendoData = async (productId: string, subscriberId: string) => {
  const baseUrl = `https://api.okendo.io/v1/stores/${subscriberId}/products/shopify-${productId}/reviews?limit=${DEFAULT_REVIEW_COUNT}&orderBy=${DEFAULT_REVIEW_ORDER}`;
  const aggregateUrl = `https://api.okendo.io/v1/stores/${subscriberId}/products/shopify-${productId}/review_aggregate`;

  const allReviews: Review[] = [];
  let aggregateRating: { ratingValue?: number; reviewCount?: number } = {};

  try {
    const response = await fetch(baseUrl);
    if (!response.ok) {
      console.warn(`Warning: Error fetching reviews: ${response.statusText}`);
      return { reviews: allReviews };
    }
    const okendoResults = await response.json();

    const reviews: Review[] = okendoResults.reviews.map((review: OkendoReview) => ({
      author: {
        name: review.reviewer.displayName,
      },
      reviewRating: {
        ratingValue: review.rating,
      },
    }));

    allReviews.push(...reviews);

    const aggregateResponse = await fetch(aggregateUrl);
    if (!aggregateResponse.ok) {
      console.warn(`Warning: Error fetching aggregate rating: ${aggregateResponse.statusText}`);
      return { reviews: allReviews };
    }

    const { reviewAggregate } = await aggregateResponse.json();

    if (reviewAggregate.reviewCount === 0) {
      console.warn("No reviews available to calculate the rating.");
      return { reviews: allReviews };
    }
    const averageRating = (
      reviewAggregate.ratingAndReviewValuesTotal / reviewAggregate.ratingAndReviewCount
    ).toFixed(1);
    aggregateRating = {
      ratingValue: +averageRating,
      reviewCount: reviewAggregate.reviewCount,
    };

    return { reviews: allReviews, aggregateRating };
  } catch (error) {
    console.warn("Warning: Failed to fetch data from Okendo:", error);
    return { reviews: allReviews, aggregateRating };
  }
};

