import { getSearchData } from "@queries/getSearchData";
import { i18nLocales } from "@typings/i18n";
import type { NextApiRequest, NextApiResponse } from "next";
import { i18n } from "next-i18next.config";

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  const locale = (req.query.locale ?? i18n.defaultLocale) as i18nLocales;

  try {
    const searchPages = await getSearchData(locale as i18nLocales);

    res
      .status(200)
      .setHeader(
        "Cache-Control",
        "public, max-age=3600, s-maxage=1800, stale-while-revalidate=86400, stale-if-error=86400"
      )
      .json({
        pages: searchPages.map(({ productDiscountCode, ...page }) => page),
      });
  } catch (error: any) {
    res
      .status(500)
      .send({ error: { message: "Failed to fetch search data", details: error?.message } });
  }
}

