import { graphqlClient } from "@getGraphqlClient";
import { SEARCH } from "@graphql/search";
import { i18nLocales } from "@typings/i18n";
import { FlattenedSearchData } from "@typings/search";
import { oneQuantity } from "@utils/constants/pdp";
import { isDevelopmentMode } from "@utils/helpers/environments/flags";
import { flattenStrapi } from "@utils/helpers/flattenStrapi";
import { getCurrentTime } from "@utils/helpers/getCurrentTime";
import { getPagesPrices } from "./getPagesPrices";

export const getSearchData = async (locale: i18nLocales) => {
  const queryParams = {
    locale,
    isDevelopmentMode,
    currentTime: getCurrentTime(),
  };

  const res = await graphqlClient.request(SEARCH, queryParams);

  const { pages, promos } = flattenStrapi(res) as FlattenedSearchData;

  const pagesWithPrices = await getPagesPrices(pages, promos, oneQuantity);

  return pagesWithPrices;
};

