import { Query } from "@generated/strapiGraphqlPresell";
import { i18nLocales } from "@typings/i18n";
import {
  BRANDLED_DATA_QUERY,
  EDITORIAL_DATA_QUERY,
  HYBRID_DATA_QUERY,
  QUIZ_DATA_QUERY,
} from "@graphql";
import { PageTypes, PresellTypes } from "@stores/presellStore";
import { graphqlClientPresell } from "@getGraphqlClientPresell";
import { SSR_PAGE_LIMIT } from "@utils/constants/graphql";

type KeyType = "editorials" | "quizzes" | "brandleds" | "hybrids";

export type GetPresellDataProps = {
  path: string;
  locale: i18nLocales;
  angle?: string;
  pageType?: PageTypes;
  key?: KeyType;
};

const QUERIES: Record<string, string> = {
  editorial: EDITORIAL_DATA_QUERY,
  quiz: QUIZ_DATA_QUERY,
  brandled: BRANDLED_DATA_QUERY,
  hybrid: HYBRID_DATA_QUERY,
};

export const getPresellData = async <T extends PresellTypes>(
  props: GetPresellDataProps
): Promise<T | null> => {
  const { path, locale, angle, pageType = "quiz", key = "quizzes" } = props;
  const urlPath = path.charAt(0) === "/" ? path : `/${path}`;
  const query = QUERIES[pageType];
  const res = (await graphqlClientPresell.request(query, {
    urlPath,
    locale,
    pageLimit: SSR_PAGE_LIMIT,
  })) as Pick<Query, KeyType>;

  if (!res[key] || res[key].length <= 0) {
    console.error(`No ${key} found for ${urlPath}`);
    return null;
  }

  return res[key].find((presell) => presell?.angle === (angle ? angle : null)) as T;
};

