     8→import { validateRequiredRelations } from "@utils/helpers/validateRequiredRelations";
     9→import { applyBannerOverrides } from "../components/applyBannerOverrides";
    10→import { applyPageOverrides } from "../components/applyPageOverrides";
    11→import { applyThemeOverrides } from "../components/applyThemeOverrides";
    12→import { ExtendedPageEntity } from "../types";
    13→import { findFeature } from "../utils/findFeature";
    14→import { findPageOverrides } from "../utils/findPageOverrides";
    15→
    16→type PromoOverrides = (
    17→  page: PageEntity,
    18→  promos: PromoEntityResponseCollection | null,
    19→  variantId?: string | null,
    20→  campaignId?: string | null
    21→) => ExtendedPageEntity;
    22→
    23→export const applyPromoOverrides: PromoOverrides = (page, promos, variantId, campaignId) => {
    24→  // gets the promo active on current page
    25→  const promo = promos?.data?.find((promo) => {
    26→    const override =
    27→      promo && findPageOverrides("PromoEntity", promo, page.id, variantId, campaignId);
    28→    if (override) {
    29→      validateRequiredRelations(override, "Promo");
    30→      return true;
    31→    }
    32→  });
    33→  // return if no active promos were found for the current page
    34→  if (!promo || !promo.attributes) return page;
    35→
    36→  let pageWithOverrides: ExtendedPageEntity;
    37→
    38→  // get the overrides
    39→  const pageOverrides = findPageOverrides("PromoEntity", promo, page.id, variantId, campaignId);
    40→  const theme = findFeature<ComponentFeatureTheme>("ComponentFeatureTheme", promo);
    41→  const banner = findFeature<ComponentFeatureBanner>("ComponentFeatureBanner", promo);
    42→  const promoMessage = findFeature<ComponentFeaturePromoMessage>(
    43→    "ComponentFeaturePromoMessage",
    44→    promo
    45→  );
    46→
    47→  // apply overrides
    48→  pageWithOverrides = applyPageOverrides(page, pageOverrides);
    49→  pageWithOverrides = applyThemeOverrides(pageWithOverrides, theme);
    50→  pageWithOverrides = applyBannerOverrides(pageWithOverrides, banner);
    51→
    52→  // adds a promo property to Page
