import {
  ComponentFeatureBanner,
  ComponentFeaturePromoMessage,
  ComponentFeatureTheme,
  PageEntity,
  PromoEntityResponseCollection,
} from "@generated/strapiGraphql";
import { validateRequiredRelations } from "@utils/helpers/validateRequiredRelations";
import { applyBannerOverrides } from "../components/applyBannerOverrides";
import { applyPageOverrides } from "../components/applyPageOverrides";
import { applyThemeOverrides } from "../components/applyThemeOverrides";
import { ExtendedPageEntity } from "../types";
import { findFeature } from "../utils/findFeature";
import { findPageOverrides } from "../utils/findPageOverrides";

type PromoOverrides = (
  page: PageEntity,
  promos: PromoEntityResponseCollection | null,
  variantId?: string | null,
  campaignId?: string | null
) => ExtendedPageEntity;

export const applyPromoOverrides: PromoOverrides = (page, promos, variantId, campaignId) => {
  // gets the promo active on current page
  const promo = promos?.data?.find((promo) => {
    const override =
      promo && findPageOverrides("PromoEntity", promo, page.id, variantId, campaignId);
    if (override) {
      validateRequiredRelations(override, "Promo");
      return true;
    }
  });
  // return if no active promos were found for the current page
  if (!promo || !promo.attributes) return page;

  let pageWithOverrides: ExtendedPageEntity;

  // get the overrides
  const pageOverrides = findPageOverrides("PromoEntity", promo, page.id, variantId, campaignId);
  const theme = findFeature<ComponentFeatureTheme>("ComponentFeatureTheme", promo);
  const banner = findFeature<ComponentFeatureBanner>("ComponentFeatureBanner", promo);
  const promoMessage = findFeature<ComponentFeaturePromoMessage>(
    "ComponentFeaturePromoMessage",
    promo
  );

  // apply overrides
  pageWithOverrides = applyPageOverrides(page, pageOverrides);
  pageWithOverrides = applyThemeOverrides(pageWithOverrides, theme);
  pageWithOverrides = applyBannerOverrides(pageWithOverrides, banner);

  // adds a promo property to Page
  // required for showing promo message and promo banner/timer on Funnels/PDPs
  if (pageWithOverrides.attributes)
    pageWithOverrides.attributes.promo = {
      id: promo.id,
      title: promo.attributes.title,
      promoMessage: promoMessage,
      showTimer: promo.attributes.showTimer,
      endDateTime: promo.attributes.endDateTime,
      isEcomEnabled: promo.attributes.isEcomEnabled,
    };
  return pageWithOverrides;
};

