import { ProductPrice } from "@typings/product";
import { formatPricesData } from "@utils/helpers/formatPricesData";

type TotalPricing = {
  line_item_price: number;
  discounted_unit_price: number;
  discounted_line_item_price: number;
  line_item_discount_amount: number;
  line_item_discount_percentage: number;
  is_free: boolean;
};

type LineItem = {
  product_id: number;
  quantity: number;
  sku: string;
  schedule: string;
  product_name: string;
  pet_size: string;
  image_url: string;
  is_upsell: boolean;
  pricing: TotalPricing;
};

type OrderResult = {
  formattedOrderData: ProductPrice[];
  formattedPrices: Record<string, any>;
  allCheckoutData: Record<string, any>;
};

export type CheckoutApiResponse = {
  data: {
    line_items: LineItem[];
    pricing: TotalPricing;
  };
};

const formatOrderData = (results: CheckoutApiResponse): ProductPrice[] => {
  return results.data.line_items.map((item) => ({
    product_id: `${item.product_id}`,
    quantity: item.quantity,
    title: item.product_name,
    price: item.pricing.line_item_price,
    schedule: item.schedule,
    discounted_price: item.pricing.discounted_line_item_price,
    country: "US",
    image: item.image_url,
    split_price: item.pricing.discounted_line_item_price,
    perceived_rrp: item.pricing.line_item_price,
    splitFlag: false,
    title_index: `0`,
    variant_id: `${item.product_id}`,
  }));
};

export const getOrderData = async (
  token: string | null,
  abortController: AbortController
): Promise<OrderResult | null> => {
  if (!token) {
    console.error("Token is required");
    return null;
  }

  try {
    const response = await fetch(
      `${process.env.NEXT_PUBLIC_VARIANT_API_V2_URL}/checkout/${token}`,
      {
        method: "GET",
        headers: {
          "Content-Type": "application/json",
        },
        signal: abortController.signal,
      }
    );

    const data: CheckoutApiResponse = await response.json();
    const formattedOrderData = formatOrderData(data);
    const formattedPrices = formatPricesData(data);
    const allCheckoutData = { ...data };

    return {
      formattedOrderData,
      formattedPrices,
      allCheckoutData,
    };
  } catch (e) {
    console.error("Error fetching order data:", e);
    return null;
  }
};

