import { i18nLocales } from "@typings/i18n";
import { NextApiRequest, NextApiResponse } from "next";
import { i18n } from "next-i18next.config";

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  try {
    const locale = (req.query.locale ?? i18n.defaultLocale) as i18nLocales;
    const data = await getNavAndConfigData(locale);

    res
      .status(200)
      .setHeader("Access-Control-Allow-Origin", "*")
      .setHeader("Access-Control-Allow-Methods", "GET, HEAD")
      .json(data);
  } catch (error: any) {
    res
      .status(500)
      .send({ error: { message: "Failed to fetch nav data", details: error?.message } });
  }
}

