import {
  EcomConfigEntityResponse,
  Maybe,
  PromoEntityResponseCollection,
  Query,
} from "@generated/strapiGraphql";
import { graphqlClient } from "@getGraphqlClient";
import { NAVIGATION_AND_CONFIG } from "@graphql/navigation";
import { NAVIGATION_AND_CONFIG_FORCED_PROMO } from "@graphql/navigationSinglePromo";
import { i18nLocales } from "@typings/i18n";
import { FlattenedNavigationAndConfig } from "@typings/navigation";
import { NAV_CACHE_PATH } from "@utils/constants/prebuild";
import { flattenStrapi } from "@utils/helpers/flattenStrapi";
import { getCachedData } from "@utils/helpers/getCachedData/getCachedData";
import { getCurrentTime } from "@utils/helpers/getCurrentTime";
import { applyEcomConfigOverrides } from "./overrides/entities/applyEcomConfigOverrides";

export const getNavAndConfigData = async (locale: i18nLocales) => {
  const cachedData = await getCachedData(NAV_CACHE_PATH, locale, "Navigation");
  if (cachedData !== null) return cachedData;

  const forcedPromoId = process.env.NEXT_PUBLIC_FORCED_PROMO_ID ?? "Active";
  const getActivePromos = forcedPromoId === "Active";

  const res = (await graphqlClient.request(
    getActivePromos ? NAVIGATION_AND_CONFIG : NAVIGATION_AND_CONFIG_FORCED_PROMO,
    {
      currentTime: getCurrentTime(),
      promoId: forcedPromoId,
      ...(locale ? { locale } : {}),
    }
  )) as Query & {
    draftPromos: Maybe<PromoEntityResponseCollection>;
    livePromos: Maybe<PromoEntityResponseCollection>;
  };

  const promos = getActivePromos ? res.promos : res.draftPromos ?? res.livePromos;

  // apply ecom header overrides
  res.ecomConfig = applyEcomConfigOverrides(res.ecomConfig, promos) as EcomConfigEntityResponse;

  const { ecomConfig, navigations, navigationCollections } = flattenStrapi(
    res
  ) as FlattenedNavigationAndConfig;

  return {
    ecomConfigData: ecomConfig,
    navigationData: navigations,
    navigationCollectionsData: navigationCollections,
  };
};

