import { Query } from "@generated/strapiGraphql";
import { graphqlClient } from "@getGraphqlClient";
import { PAGE_QUERY } from "@graphql/page";
import { i18nLocales } from "@typings/i18n";
import { isDevelopmentMode } from "@utils/helpers/environments/flags";

export const getPage = async (path: string, isEcom: boolean, locale: i18nLocales) => {
  const urlPath = path.charAt(0) === "/" ? path : `/${path}`;

  const res = (await graphqlClient.request(PAGE_QUERY, {
    path: urlPath,
    isEcom,
    locale,
    isDevelopmentMode,
  })) as Pick<Query, "pages">;

  if (!res.pages?.data || res.pages.data.length <= 0) {
    console.error(`No page found for /${locale}${isEcom ? "/products" : ""}${urlPath}`);
    return null;
  }

  if (!res.pages.data[0].attributes?.products?.data.length) {
    console.error(`No products found for ${locale}${isEcom ? "/products" : ""}${urlPath}`);
    return null;
  }

  return res.pages.data[0];
};

