import { gql } from "graphql-request";
import { COMMON_IMAGE_FRAGMENT } from "./fragments/common";
import { DISCOUNT_CODE_FRAGMENT } from "./fragments/entities/discountCode";
import { PAGE_FEATURES } from "./fragments/features";
import { PAGE_COMMON } from "./fragments/page";

export const PAGE_PATHS_QUERY = gql`
  query PagePaths(
    $locale: I18NLocaleCode
    $pageLimit: Int
    $isEcom: Boolean!
    $isDevelopmentMode: Boolean
  ) {
    pages(
      locale: $locale
      pagination: { limit: $pageLimit }
      filters: { isEcom: { eq: $isEcom }, isDevelopmentMode: { eq: $isDevelopmentMode } }
    ) {
      data {
        id
        attributes {
          publishedAt
          urlPath
          locale
          isEcom
          title
          seo {
            isIndexable
          }
        }
      }
    }
    pageVariants(
      locale: $locale
      pagination: { limit: $pageLimit }
      filters: { isDevelopmentMode: { eq: $isDevelopmentMode } }
    ) {
      data {
        attributes {
          urlPath
          overrides {
            ... on ComponentOverridesPageOverrides {
              page {
                data {
                  attributes {
                    urlPath
                    publishedAt
                  }
                }
              }
            }
          }
        }
      }
    }
  }
`;

export const PAGE_QUERY = gql`
  ${PAGE_COMMON}
  ${PAGE_FEATURES}
  query Page(
    $locale: I18NLocaleCode
    $path: String!
    $isEcom: Boolean!
    $isDevelopmentMode: Boolean
  ) {
    pages(
      locale: $locale
      filters: {
        urlPath: { eq: $path }
        isEcom: { eq: $isEcom }
        isDevelopmentMode: { eq: $isDevelopmentMode }
      }
    ) {
      data {
        id
        attributes {
          ...PageCommon
        }
      }
    }
  }
`;

export const PDP_FREE_GIFTS_QUERY = gql`
  query PdpFreeGifts($locale: I18NLocaleCode) {
    freeGiftOffers(locale: $locale) {
      data {
        id
        attributes {
          __typename
          productID
        }
      }
    }
  }
`;

export const PAGE_ALL_PDPS_QUERY = gql`
  ${DISCOUNT_CODE_FRAGMENT}
  ${COMMON_IMAGE_FRAGMENT}
  query PageAllPdps(
    $locale: I18NLocaleCode
    $pageLimit: Int
    $isEcom: Boolean!
    $isDevelopmentMode: Boolean
  ) {
    pages(
      locale: $locale
      pagination: { limit: $pageLimit }
      filters: { isEcom: { eq: $isEcom }, isDevelopmentMode: { eq: $isDevelopmentMode } }
    ) {
      data {
        id
        attributes {
          urlPath
          locale
          isEcom
          title
          seo {
            hideFromAllPdps
          }
          heroImages {
            id
            subHeroImage {
              ...ImageCommonFragment
            }
            otpHeroImage {
              ...ImageCommonFragment
            }
          }
          products {
            data {
              attributes {
                heroImages {
                  id
                  subHeroImage {
                    ...ImageCommonFragment
                  }
                  otpHeroImage {
                    ...ImageCommonFragment
                  }
                }
              }
            }
          }
          productDiscountCode {
            ...DiscountCodeFragment
          }
          feature {
            ... on ComponentFeaturePurchaseOptions {
              purchaseTypeDetails
              quantitySelector
            }
          }
          subFreeGiftOffer {
            data {
              attributes {
                variantId
                productName
                productID
                rrpPrice
              }
            }
          }
          subBumpOffers {
            data {
              attributes {
                label
                productSubID
                subscriptionVariantID
                discountCode {
                  data {
                    attributes {
                      code
                    }
                  }
                }
              }
            }
          }
          otpBumpOffers {
            data {
              attributes {
                label
                productOtpID
                otpVariantID
                discountCode {
                  data {
                    attributes {
                      code
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
    pageVariants(
      locale: $locale
      pagination: { limit: $pageLimit }
      filters: { isDevelopmentMode: { eq: $isDevelopmentMode } }
    ) {
      data {
        attributes {
          urlPath
          overrides {
            ... on ComponentOverridesPageOverrides {
              page {
                data {
                  attributes {
                    isEcom
                    urlPath
                    publishedAt
                  }
                }
              }
            }
          }
        }
      }
    }
  }
`;

