import { PromoEntityResponseCollection, Query } from "@generated/strapiGraphql";
import { graphqlClient } from "@getGraphqlClient";
import { COLLECTION_PAGE_QUERY } from "@graphql/collections";
import { getPagesPrices } from "@queries/getPagesPrices";
import { applyCollectionOverrides } from "@queries/overrides/entities/applyCollectionOverrides";
import { FlattenedCollectionsResponse, GetCollectionsReturnType } from "@typings/collections";
import { i18nLocales } from "@typings/i18n";
import { oneQuantity } from "@utils/constants/pdp";
import { COLLECTIONS_CACHE_PATH } from "@utils/constants/prebuild";
import { isDevelopmentMode } from "@utils/helpers/environments/flags";
import { flattenStrapi } from "@utils/helpers/flattenStrapi";
import { getCachedData } from "@utils/helpers/getCachedData";

export const getCollections = async (
  locale: i18nLocales,
  promos: PromoEntityResponseCollection | null
) => {
  const cachedData = await getCachedData(COLLECTIONS_CACHE_PATH, locale, "Collections");
  if (cachedData !== null) return cachedData as GetCollectionsReturnType;

  const res = (await graphqlClient.request(COLLECTION_PAGE_QUERY, {
    isDevelopmentMode,
    ...(locale ? { locale } : {}),
  })) as Query;

  // adds additional page override fields to pages with an active promo
  const pages = flattenStrapi(applyCollectionOverrides(res.pages, promos));
  const pagesWithPrices = await getPagesPrices(pages, null, oneQuantity);

  const collections = flattenStrapi(res) as FlattenedCollectionsResponse;

  return {
    categories: collections.categories,
    tags: collections.tags,
    commonIssues: collections.commonIssues,
    pages: pagesWithPrices,
    collections: collections?.collections,
  } as GetCollectionsReturnType;
};

