import { BANNER_COMPONENT_FRAGMENT } from "@graphql/fragments/components";
import { gql } from "graphql-request";
import { COMMON_IMAGE_FRAGMENT } from "./fragments/common";

export const COLLECTION_PAGE_PATHS_QUERY = gql`
  query CollectionPagePaths($locale: I18NLocaleCode) {
    categories(locale: $locale) {
      data {
        id
        attributes {
          urlPath
          publishedAt
        }
      }
    }
  }
`;

export const COLLECTION_PAGE_QUERY = gql`
  ${COMMON_IMAGE_FRAGMENT}
  ${BANNER_COMPONENT_FRAGMENT}
  query CollectionPage($locale: I18NLocaleCode, $isDevelopmentMode: Boolean) {
    collections(locale: $locale) {
      data {
        attributes {
          banner {
            ...BannerComponentFragment
          }
        }
      }
    }
    commonIssues(locale: $locale) {
      data {
        id
        attributes {
          name
          urlPath
          pages(filters: { isEcom: { eq: true } }, pagination: { limit: 35 }) {
            data {
              id
            }
          }
        }
      }
    }
    tags(locale: $locale) {
      data {
        id
        attributes {
          name
          urlPath
          pages(filters: { isEcom: { eq: true } }, pagination: { limit: 35 }) {
            data {
              id
            }
          }
        }
      }
    }
    categories(locale: $locale, sort: "rank") {
      data {
        id
        attributes {
          createdAt
          updatedAt
          name
          title
          description
          seo {
            title
            description
            isIndexable
            keywords
            ogImage {
              data {
                id
                attributes {
                  url
                  width
                  height
                }
              }
            }
          }
          vetQuote {
            data {
              id
              attributes {
                quote
                vet {
                  data {
                    attributes {
                      fullname
                      honours
                      short_description
                      avatar {
                        data {
                          attributes {
                            url
                            width
                            height
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
          urlPath
          pages(filters: { isEcom: { eq: true } }, pagination: { limit: 35 }) {
            data {
              id
            }
          }
        }
      }
    }
    pages(
      locale: $locale
      filters: { isEcom: { eq: true }, isDevelopmentMode: { eq: $isDevelopmentMode } }
      pagination: { limit: 35 }
    ) {
      data {
        id
        attributes {
          title
          urlPath
          shortDescription
          okendoStarRating
          subFreeGiftOffer {
            data {
              attributes {
                rrpPrice
              }
            }
          }
          productDiscountCode {
            data {
              attributes {
                code
                perceivedDiscountPercentage
                perceivedOtpDiscountPercentage
              }
            }
          }
          products {
            data {
              id
              attributes {
                isSoldOut
                subscriptionVariantID
                otpVariantID
                productOtpID
                productSubID
                name
                petType
                image {
                  ...ImageCommonFragment
                }
              }
            }
          }
        }
      }
    }
  }
`;

