import { COMMON_PRODUCT_FRAGMENT } from "@graphql/fragments/common/product";
import { gql } from "graphql-request";
import {
  COMMON_ACTION_CARDS_FRAGMENT,
  COMMON_IMAGE_FRAGMENT,
  COMMON_MODAL_FRAGMENT,
  COMMON_SUB_FREE_GIFT_FRAGMENT,
} from "./common";
import { DISCOUNT_CODE_FRAGMENT } from "./entities/discountCode";

export const PAGE_COMMON = gql`
  ${DISCOUNT_CODE_FRAGMENT}
  ${COMMON_SUB_FREE_GIFT_FRAGMENT}
  ${COMMON_ACTION_CARDS_FRAGMENT}
  ${COMMON_MODAL_FRAGMENT}
  ${COMMON_IMAGE_FRAGMENT}
  ${COMMON_PRODUCT_FRAGMENT}
  fragment PageCommon on Page {
    isEcom
    relatedPages {
      data {
        id
        attributes {
          urlPath
          title
          productDiscountCode {
            ...DiscountCodeFragment
          }
          subFreeGiftOffer {
            data {
              attributes {
                rrpPrice
              }
            }
          }
          commonIssue {
            data {
              attributes {
                name
              }
            }
          }
          products {
            data {
              id
              attributes {
                name
