import { gql } from "graphql-request";

export const COMMON_PRODUCT_FRAGMENT = gql`
  fragment ProductFragment on ProductEntity {
    id
    attributes {
      productId
      productSubID
      productOtpID
      name
      sku
      productType
      packageType
      packageUnits
      packageUnitWeight
      subscriptionVariantID
      otpVariantID
      productsSoldRecently
      isSoldOut
      recommendedDogSize {
        data {
          id
          attributes {
            weight
            label
            icon {
              ...ImageCommonFragment
            }
          }
        }
      }
      images {
        data {
          id
          attributes {
            caption
            alternativeText
            width
            height
            url
          }
        }
      }
      image {
        ...ImageCommonFragment
      }
      heroImages {
        id
        subHeroImage {
          ...ImageCommonFragment
        }
        otpHeroImage {
          ...ImageCommonFragment
        }
      }
      ingredients(pagination: { limit: 35 }) {
        productIngredient {
          data {
            id
            attributes {
              label
              image {
                ...ImageCommonFragment
              }
              description
              fullLabel
              shortLabel
              shortDescription
              missingInCompetitors
              secondaryImage {
                ...ImageCommonFragment
              }
            }
          }
        }
        id
        amountLabel
        showAsHighlight
        isHiddenInList
        ingredientSubitems {
          label
          amountLabel
        }
        bulletPoints {
          id
          label
        }
        description
        shortDescription
      }
      inactiveIngredients
      ingredientCautions
      usageInstructions
      usageInstructionsImage {
        ...ImageCommonFragment
      }
      usageWarnings
      usageRecommendations {
        id
        dogSize {
          data {
            id
            attributes {
              weight
              label
              icon {
                ...ImageCommonFragment
              }
            }
          }
        }
        dailyAmount
        monthlyAmount
        productUnitIcon {
          ...ImageCommonFragment
        }
      }
      usageLabelKey
      klaviyoListId
      subUpsellUrl
      otpUpsellUrl
      ingredientsDescription
      productName
      petType
      numberOfItemsInPack
      parentSku {
        data {
          attributes {
            name
          }
        }
      }
      petSize
    }
  }
`;

